        { grpCd: "TL113", compID: "acb_payClsCd" }, //거래구분 콤보, 그리드의 거래구분 콤보

        { grpCd: "TL103", compID: "gr_oilUnitPrice:oilTskClsCd" }, //그리드의 유류업무 구분 콤보
