        { grpCd: "TL101", compID: "gr_oilUnitPrice:selpchClsCd" }, //그리드의 매출입 구분 콤보
        //{ grpCd: "TL201", compID: "gr_oilUnitPrice:selpchClntNm_H" }, //그리드의 매입거래처명 히든 콤보
        { grpCd: "ZZ701", compID: "gr_oilUnitPrice:oilingPurpsCd" }, //그리드의 주유용도 콤보
