    }

    ds_grPreCoAfClsCd.insertRow(0);
    ds_grPreCoAfClsCd.setCellData(0,"cd","");
    ds_grPreCoAfClsCd.setCellData(0,"cdNm","");

    $p.getComponentById(acb_preCoAfClsCd.getDataListInfo().id).insertRow(0);
    $p.getComponentById(acb_preCoAfClsCd.getDataListInfo().id).setCellData(0,"cd","");
