        ds_grOilkndCd.setCellData(i,"cdNm",$p.getComponentById(acb_oilkndCd.getDataListInfo().id).getCellData(i,"cdNm"));
    }

    ds_grOilkndCd.insertRow(0);
    ds_grOilkndCd.setCellData(0,"cd","");
    ds_grOilkndCd.setCellData(0,"cdNm","");

    $p.getComponentById(acb_oilkndCd.getDataListInfo().id).insertRow(0);
    $p.getComponentById(acb_oilkndCd.getDataListInfo().id).setCellData(0,"cd","");
    $p.getComponentById(acb_oilkndCd.getDataListInfo().id).setCellData(0,"cdNm","선택");


    for(var i=0;i<$p.getComponentById(acb_payClsCd.getDataListInfo().id).getRowCount();i++) {
