        ds_grPayClsCd.setCellData(i,"cd",$p.getComponentById(acb_payClsCd.getDataListInfo().id).getCellData(i,"cd"));
        ds_grPayClsCd.setCellData(i,"cdNm",$p.getComponentById(acb_payClsCd.getDataListInfo().id).getCellData(i,"cdNm"));
