scwin.onUdcCompleted = function() {
    ed_stdDt.setValue(new Date().format("YYYYMM") + "01");
    ed_endDt.setValue(new Date().format("YYYYMMDD"));
};

scwin.f_CheckAdptDt = async function() {
    var vAdptStDt = ed_stdDt.getValue();
	var vAdptEndDt = ed_endDt.getValue();
	var vReturn = true;

	if(vAdptStDt == "" || vAdptStDt.length < 8) {
		await $c.win.alert("적용시작일자를 정확하게 입력해주십시오.");
		ed_stdDt.focus();
		vReturn =  false;
	}

	if(vAdptEndDt == "" || vAdptEndDt.length < 8) {
		await $c.win.alert("적용종료일자를 정확하게 입력해주십시오.");
		ed_endDt.focus();
		vReturn =  false;
	}

	if(Number(vAdptStDt) > Number(vAdptEndDt)){
		await $c.win.alert("적용시작일자가 종료일자보다 늦은 날짜입니다.");
		ed_stdDt.focus();
		vReturn =  false;
	}
	return vReturn;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    var vChkVal = await scwin.f_CheckAdptDt();			//날짜 체크한 결과 값을 리턴
	if(!vChkVal){					//true or false 결과을 체크하여 잘못들어갔다면, false값 리턴
		return false;
	}

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_retrieve);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_retrieve_submitdone();
    }	
};

scwin.sbm_retrieve_submitdone = async function (e) {
    totalRows.setValue(ds_oilUnitPrice.getRowCount());

    if (ds_oilUnitPrice.getRowCount() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	}


    gr_oilUnitPrice.setReadOnly("column",'ioDt', true);					//입고일자
   	gr_oilUnitPrice.setReadOnly("column",'oilStatNm', true);					//주유소명
	gr_oilUnitPrice.setReadOnly("column",'oilkndCd', true);					//유종구분
	gr_oilUnitPrice.setReadOnly("column",'oilTskClsCd', true);					//유류업무구분
	gr_oilUnitPrice.setReadOnly("column",'oilBizClsCd', true);					//유류사업구분
	gr_oilUnitPrice.setReadOnly("column",'preCoAfClsCd', true);					//판매구분
	gr_oilUnitPrice.setReadOnly("column",'selpchClsCd', true);					//매출입구분
	gr_oilUnitPrice.setReadOnly("column",'selpchClntNo', true);					//매입거래처
	gr_oilUnitPrice.setReadOnly("column",'stockAcctDeptNm', true);					//상품귀속부서
	gr_oilUnitPrice.setReadOnly("column",'homeClsCd', true);					//소속구분코드
	gr_oilUnitPrice.setReadOnly("column",'stockAcctDeptCd', true);					//상품귀속부서코드


    for(var i=0;i<ds_oilUnitPrice.getRowCount();i++) {
        if(ds_oilUnitPrice.getCellData(i,"fmsYn") == "Y"){
            gr_oilUnitPrice.setReadOnly("cell",i,'selfTransYn', true);				//자가운송여부
            gr_oilUnitPrice.setReadOnly("cell",i,'qty', true);				//수량
            gr_oilUnitPrice.setReadOnly("cell",i,'bpClntNo', true);				//운송거래처
        }else {
            gr_oilUnitPrice.setReadOnly("cell",i,'selfTransYn', false);					//자가운송여부
            gr_oilUnitPrice.setReadOnly("cell",i,'qty', false);					//수량
            gr_oilUnitPrice.setReadOnly("cell",i,'bpClntNo', false);
            gr_oilUnitPrice.setCellInputType(i, "bpClntNo", {inputType : "textImage"});					//운송거래처
        }

        if (ds_oilUnitPrice.getCellData(i,"slipNo") != ""){
            gr_oilUnitPrice.setReadOnly("cell",i,'rmk', true);				//적요
            gr_oilUnitPrice.setReadOnly("cell",i,'slipDt', true);				//전표일자
        }else {
            if (ds_oilUnitPrice.getCellData(i,"payClsCd") == "10"){
                gr_oilUnitPrice.setReadOnly("cell",i,'rmk', false);
                gr_oilUnitPrice.setReadOnly("cell",i,'slipDt', false);
            } else if (ds_oilUnitPrice.getCellData(i,"payClsCd") == "01"){
                gr_oilUnitPrice.setReadOnly("cell",i,'rmk', true);
                gr_oilUnitPrice.setReadOnly("cell",i,'slipDt', true);
            }
        }
    }
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    if(ds_oilUnitPrice.getModifiedIndex().length == 0) {
	  await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ['유류입고 그리드'] );	//정보 없음
	  return;
	}

    debugger;
    let ret = await $c.gus.cfValidate([gr_oilUnitPrice]);
    if (!ret) {
        return;
    }

	// 입력한 경우에 대해서는 입력수량과 수량 일치시킴.
	for ( var k=0; k < ds_oilUnitPrice.getRowCount(); k++ ) {
		var stdYm = "";
        var payClsCd = ds_oilUnitPrice.getCellData(k, "payClsCd");
		if ( ds_oilUnitPrice.getRowStatus(k) == "C" || ds_oilUnitPrice.getRowStatus(k) == "U" ) {
			if ( payClsCd == "10" ) {
				let bRtn = await scwin.f_calcAmt(k);		// 현물 구매단가
                /*
                if (!bRtn) {
                    return;
                }
                */
			}
			if ( ds_oilUnitPrice.getCellData(k, "insYn") == "1" ) {
				ds_oilUnitPrice.setCellData(k, "insQty", ds_oilUnitPrice.getCellData(k, "qty"));
			}
		}
		if ( ds_oilUnitPrice.getRowStatus(k) == "C" && payClsCd == "01" ) {
			ds_oilUnitPrice.setCellData(k, "upr", 0);
			ds_oilUnitPrice.setCellData(k, "amt", 0);
		}

		// 해당월 유류 마감여부 체크
		if ( ds_oilUnitPrice.getRowStatus(k) == "C" || ds_oilUnitPrice.getRowStatus(k) == "D" || ds_oilUnitPrice.getRowStatus(k) == "U" ) {
			stdYm = ds_oilUnitPrice.getCellData(k, "ioDt").substring(0,6);
	        let rtn1 = await udc_closeYn.cfJobCloseYN("CUR", stdYm, "00", "EQ07", "00", "", "N");
            if (rtn1 == "2") {
		    	await $c.win.alert(stdYm + "월 FMS유류업무를 이미 마감하였습니다. 구매팀 담당자에게 문의하세요.");
		    	return;
            }
            var upr = ds_oilUnitPrice.getCellData(k, "upr");
			if ( payClsCd == "10" && upr == "0" ) {
				await $c.win.alert("현물거래인 경우 단가가 등록되어야 합니다. 단가를 확인하세요");
                ds_oilUnitPrice.setRowPosition(k);
				return;
			}
		}
	}

    let rtn2 = await $c.win.confirm(MSG_CM_CRM_001);

	if(rtn2) { 	// 저장 확인
		//submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_saveOilPrice);

        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
            await scwin.sbm_saveOilPrice_submitdone();
        }
	}
};

scwin.sbm_saveOilPrice_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	
};

//-------------------------------------------------------------------------
// 체크
//-------------------------------------------------------------------------
scwin.isGrdDupDataFlag = async function (grdObj, strGrdNm, colObj) {
    var sRtn = false;

    let hVal = "",
        tHval = "";
    let dataListObj = $p.getComponentById(grdObj.getDataList());

    // alert 출력을 위해서 헤더 정보값을 만든다
    for (let idx in colObj) {
        hVal = grdObj.getHeaderValue(grdObj.getHeaderID(grdObj.getColumnIndex(colObj[idx]))) || "이름없음";
        hVal = hVal.replace(/<[^>]*>/gi, "").replace(" ","");
        if(tHval.length == 0) {
            tHval = hVal;
        } else {
            tHval = tHval + ", " + hVal;
        }
    }

    // 배열에 컬럼값들 합쳐서 담기.
    let colData,rowData;
    let colChkAllData = [];
    for(var i=0;i<dataListObj.getRowCount();i++) {
        rowData = "";
        for (let idx in colObj) {
            colData = dataListObj.getCellData(i, colObj[idx]);
            if(idx == 0) {
                rowData = colData;
            } else {
                rowData = rowData + colData;
            }  
        }
        colChkAllData.push(rowData);
    }

    // 데이터 중복 체크
    const result = {};
    let dupIdx;
    sRtn =  colChkAllData.some((value, key) => {
                result[value] = (result[value] || 0) + 1;
                if (result[value] > 1) {
                    dupIdx = key+1;
                    return true;
                }
            });

    if (sRtn && (dupIdx != undefined && dupIdx != null && dupIdx != "")) {
        await $c.win.alert(strGrdNm + "의 " + dupIdx + "번째 데이터에서 " + tHval + "은(는) 중복될 수 없습니다.");
        scwin.sleep(50).then(function () {
            if(gr_oilUnitPrice.getFocusedColumnID() != undefined && gr_oilUnitPrice.getFocusedColumnID() != null && gr_oilUnitPrice.getFocusedColumnID() != "") {
                grdObj.setFocusedCell(dupIdx-1, gr_oilUnitPrice.getFocusedColumnID());
            } else {
                grdObj.setFocusedCell(dupIdx-1, colObj[colObj.length-1]);
            }            
        });
    }

    return sRtn;
};

scwin.f_Check = async function() {
    if(!$c.gus.cfValidateGrid(gr_oilUnitPrice)){
		return false;
	}

    let ret = await scwin.isGrdDupDataFlag(gr_oilUnitPrice, "유류입고등록", ["ioDt", "oilStatNm", "preCoAfClsCd","oilkndCd","selpchClntNo","sellClntNo","payClsCd","qty","regDt"])
    if(ret) {
        return false;
    }

	return true;
};


//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_AddRow = async function() {
    let rtn = await scwin.f_Check();
    if(!rtn){
		return;
	}

	var payClsCd = "";
	payClsCd = acb_payClsCd.getValue();
	if ( payClsCd == "" ) {
		payClsCd = "01";		// 여신거래
	}
    var nRow = ds_oilUnitPrice.getRowCount();
	// oilTskClsCd 기본값 셋팅 F로
   	ds_oilUnitPrice.insertRow(nRow);
   	ds_oilUnitPrice.setCellData(nRow, 'oilTskClsCd', "F");							//유류업무구분
   	ds_oilUnitPrice.setCellData(nRow, 'oilBizClsCd', "01");							//유류사업구분
   	ds_oilUnitPrice.setCellData(nRow, 'selpchClsCd', "01");							//매출입구분(매입)
   	ds_oilUnitPrice.setCellData(nRow, 'oilkndCd', "01");							//유류구분:경유
   	ds_oilUnitPrice.setCellData(nRow, 'homeClsCd', "F");							//소속구분
   	ds_oilUnitPrice.setCellData(nRow, 'ioDt', new Date().format("YYYYMMDD"));
   	ds_oilUnitPrice.setCellData(nRow, 'seq', "1");							//초기값 셋팅
   	ds_oilUnitPrice.setCellData(nRow, 'ioClsCd', "I");							//입고
   	ds_oilUnitPrice.setCellData(nRow, 'oilRcpayPatternCd', "IP");							//매입
	ds_oilUnitPrice.setCellData(nRow, 'pcostAcctDeptCd', scwin.deptCd);						//원가귀속(사용안함)
	ds_oilUnitPrice.setCellData(nRow, 'stockAcctDeptCd', scwin.deptCd);						//재고귀속(사용안함)
	ds_oilUnitPrice.setCellData(nRow, 'selpchClntNo', scwin.clntNo);						//매입거래처
	ds_oilUnitPrice.setCellData(nRow, 'selpchClntNm', scwin.clntNm);						//매입거래처
	ds_oilUnitPrice.setCellData(nRow, 'selfTransYn', "0");		// 자가운송여부
	ds_oilUnitPrice.setCellData(nRow, 'insYn', "1");		// 입력여부
	ds_oilUnitPrice.setCellData(nRow, 'payClsCd', payClsCd);	// 거래구분 : 여신

    //ryu 추가.
    ds_oilUnitPrice.setCellData(nRow, 'qty', "0");	//리터
    ds_oilUnitPrice.setCellData(nRow, "upr", "0");   //단가
	ds_oilUnitPrice.setCellData(nRow, "amt", "0");   //금액

    //ryu 추가.
    gr_oilUnitPrice.setReadOnly("column",'preCoAfClsCd', false);

    gr_oilUnitPrice.setReadOnly("cell",nRow,'ioDt', false);					//입고일자
    gr_oilUnitPrice.setReadOnly("cell",nRow,'oilStatNm', false);					//주유소명
    gr_oilUnitPrice.setReadOnly("cell",nRow,'oilkndCd', false);					//유종구분
    gr_oilUnitPrice.setReadOnly("cell",nRow,'oilTskClsCd', false);					//유류업무구분
    gr_oilUnitPrice.setReadOnly("cell",nRow,'oilBizClsCd', false);					//유류사업구분
    gr_oilUnitPrice.setReadOnly("cell",nRow,'selpchClsCd', false);					//매출입구분
    gr_oilUnitPrice.setReadOnly("cell",nRow,'selpchClntNo', false);					//매입거래처
    gr_oilUnitPrice.setReadOnly("cell",nRow,'stockAcctDeptNm', false);					//상품귀속부서
    gr_oilUnitPrice.setReadOnly("cell",nRow,'selfTransYn', false);					//자가운송여부
    gr_oilUnitPrice.setReadOnly("cell",nRow,'payClsCd', false);					//거래구분

	gr_oilUnitPrice.setReadOnly("cell",nRow,'selpchClntNm', true);					//매입거래처
	gr_oilUnitPrice.setReadOnly("cell",nRow,'sellClntNm', true);					//매출거래처
	gr_oilUnitPrice.setReadOnly("cell",nRow,'stockAcctDeptNm', true);					//상품귀속부서

    gr_oilUnitPrice.setCellInputType(nRow, "oilStatNm", {inputType : "textImage"});
    gr_oilUnitPrice.setCellInputType(nRow, "selpchClntNo", {inputType : "textImage"});
    gr_oilUnitPrice.setCellInputType(nRow, "bpClntNo", {inputType : "textImage"});

    gr_oilUnitPrice.setFocusedCell(nRow, "ioDt", true);
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = async function(gubun) {
    if(ds_oilUnitPrice.getRowCount()==0){
		await $c.win.alert("삭제할 데이타가 없습니다");
		return;
	}

	if (ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition(),"fmsYn")=="Y"){
		await $c.win.alert("유류입고 확정을 통해 등록된 입고내역은 삭제하실 수 없습니다.");
		return;
	}
	if (ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition(), "slipNo") != ""){
		await $c.win.alert("유류입고 선급금전표를 생성하셨으므로 삭제하실 수 없습니다.");
		return;
	}
	ds_oilUnitPrice.deleteRow(ds_oilUnitPrice.getRowPosition());
};

//-------------------------------------------------------------------------
// 현물 구매단가 구해서 금액 계산하기
//-------------------------------------------------------------------------
scwin.f_calcAmt = async function(row) {
    var bRtn = true;
    var payClsCd = ds_oilUnitPrice.getCellData(row, "payClsCd");
	if ( payClsCd == "10" ) {
		// 날짜 Or 정유사 Or 수량이 변경되는 경우 현물단가/금액 계산 로직 추가
		dma_amt.set("oilTskClsCd" 	, ds_oilUnitPrice.getCellData(row, "oilTskClsCd"));	// 업무구분
		dma_amt.set("oilBizClsCd" 	, ds_oilUnitPrice.getCellData(row, "oilBizClsCd"));	// 사업구분
		dma_amt.set("oilkndCd" 	, ds_oilUnitPrice.getCellData(row, "oilkndCd"));		// 유종
		dma_amt.set("ioDt" 		, ds_oilUnitPrice.getCellData(row, "ioDt"));			// 입고일자
		dma_amt.set("sellClntNo" 	, ds_oilUnitPrice.getCellData(row, "sellClntNo"));		// 매출거래처
		dma_amt.set("selpchClntNo" , ds_oilUnitPrice.getCellData(row, "selpchClntNo"));	// 매입거래처(정유사)
		dma_amt.set("selfTransYn" 	, ds_oilUnitPrice.getCellData(row, "selfTransYn"));	// 자가운송여부

		// 단가 구해오기
        //submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_retrieveAmt);

        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
            let bRtn2 = await scwin.sbm_retrieveAmt_submitdone();
            bRtn = bRtn2;
        }
	}

    return bRtn;
};

scwin.sbm_retrieveAmt_submitdone = async function (e) {
    var bRtn = true;
    if ( ds_amtResult.getRowCount() > 0 ) {
        var upr = ds_amtResult.getCellData(0, "upr");

        if ( Number(upr) == 0 ) {
            await $c.win.alert( ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition(), "ioDt") + "일자 "
                    + ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition(), "sellClntNo")
                    + " 매입거래처에 대한 매입단가가 등록되어 있지 않습니다." );
            bRtn = false;
        } else {
            ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), "upr", upr);
            ds_oilUnitPrice.setCellData(ds_oilUnitPrice.getRowPosition(), "amt", Number(upr) * Number(ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition(), "qty")));
        }
    }

    return bRtn;
};



//-------------------------------------------------------------------------
// 선급금 전표 생성/삭제
//-------------------------------------------------------------------------
scwin.f_PrePaySlip = async function(confYn) {
    if (ds_oilUnitPrice.getModifiedIndex().length == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ['FMS유류입고 그리드'] );	//정보 없음
		return;
	}
    var clsCd;
	if ( confYn == "Y" ) {
		clsCd = "Y";
		scwin.clsNm = "선급금 전표생성";
	} else if ( confYn == "N" ) {
		clsCd = "N";
		scwin.clsNm = "선급금 전표삭제";
	}
    let rtn = await scwin.f_validChk(clsCd);
	if ( !rtn ) {
		return;
	}

	var chkYn = 0;
    let rtn2 = await $c.win.confirm("선택한 행에 대해 " + scwin.clsNm + "하시겠습니까?");
	if( rtn2 ){ 	// 저장 확인
		if ( confYn == "Y" ) {
            sbm_prepaySlip.action = "/ps.eq.fmsmgnt.fmsoilmgnt.CreateFmsOilPrepaySlipCMD.do";

			for ( var i=0; i<ds_oilUnitPrice.getRowCount(); i++ ) {
				chkYn = ds_oilUnitPrice.getCellData(i, "chkYn");
				if ( chkYn == "1" ) {
					if ( ds_oilUnitPrice.getCellData(i, "slipDt") == "" || ds_oilUnitPrice.getCellData(i, "rmk") == "" ) {
						await $c.win.alert("선급금 전표 생성시 전표일자, 적요는 필수입력입니다.");
						return;
					}
				}
			}
		} else if ( confYn == "N" ) {
            sbm_prepaySlip.action = "/ps.eq.fmsmgnt.fmsoilmgnt.CancelFmsOilPrepaySlipCMD.do";
		}

        //submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_prepaySlip);

        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
            await scwin.sbm_prepaySlip_submitdone();
        }
	}
};

scwin.sbm_prepaySlip_submitdone = async function (e) {
    await $c.win.alert("성공적으로 " + scwin.clsNm + "하였습니다.");
	await scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// f_validChk(clsCd) : 확정/확정취소 valid 체크
//-------------------------------------------------------------------------
scwin.f_validChk = async function(clsCd) {
    var slipNo = "";
	var chkYn = 0;
	for ( var i=0; i<ds_oilUnitPrice.getRowCount(); i++ ) {
		slipNo	 = ds_oilUnitPrice.getCellData(i, "slipNo");
		chkYn 	  = ds_oilUnitPrice.getCellData(i, "chkYn");
		if ( chkYn == "1" ) {
			if (clsCd == "Y") {
				if ( slipNo.length == 10 ) {
					await $c.win.alert((i+1) + " 행은 이미 전표생성 상태이므로 선급금 전표생성할 수 없습니다.");
					return false;
				}
			} else if (clsCd == "N") {
				if ( slipNo.length == 0 ) {
					await $c.win.alert((i+1) + "행은 이미 전표생성하지 않았으므로 선급금 전표취소할 수 없습니다.");
					return false;
				}
			}
		}
	}
	return true;
};

//-------------------------------------------------------------------------
// f_Adjust() : 현물 입고 내역 분할
//-------------------------------------------------------------------------
scwin.f_Adjust = async function() {
    var chkYn;
	var row=0;
	var chkCnt = 0;
	for ( var i=0; i<ds_oilUnitPrice.getRowCount(); i++ ) {
		chkYn = ds_oilUnitPrice.getCellData(i, "chkYn");
		if ( chkYn == "1" ) {
			chkCnt = chkCnt +1;
			row=i;
		}
	}

	var newOilOilStatCd = ed_newOilOilStatCd.getValue();
	var newQty = ed_newQty.getValue();
	var oilStatNm;
	if ( chkCnt != 1 ) {
		await $c.gus.cfAlertMsg("분할하고자 하는 입고내역을 선택하세요.");
		return;
	}
	if ( row < 0 ) {
		await $c.gus.cfAlertMsg("분할하고자 하는 입고내역을 선택하세요.");
		return;
	}
	chkYn = ds_oilUnitPrice.getCellData(row, "chkYn") ;
	if (chkYn != "1" ) {
		await $c.win.alert("분할하고자 하는 입고내역을 체크하세요.");
		return;
	}
	if ( ds_oilUnitPrice.getCellData(row, "payClsCd") == "01" || ds_oilUnitPrice.getCellData(row, "slipNo") == "" ) {
		await $c.gus.cfAlertMsg("현물입고, 선급금전표 생성건만 선급금분할 할 수 있습니다.");
		return;
	}
	if ( newOilOilStatCd == "" || Number(newQty) == 0 ) {
		await $c.gus.cfAlertMsg("분할 주유소, 리터수를 입력하세요.");
		ed_newOilOilStatCd.focus();
		return;
	}
	if ( newOilOilStatCd ==  ds_oilUnitPrice.getCellData(row, "oilOilStatNo") ) {
		await $c.gus.cfAlertMsg("분할 주유소는 기존 입고주유소와 같을 수 없습니다.");
		ed_newOilOilStatCd.focus();
		return;
	}

	oilStatNm = ds_oilUnitPrice.getCellData(row, "oilStatNm") ;
    let rtn = await $c.win.confirm("선택하신 " + oilStatNm + " 에 대해 선급금내역을 분할하시겠습니까?");
	if( rtn ){ 	//  확인
		//ds_oilUnitPrice.UseChangeInfo = "true";
		ds_oilUnitPrice.setCellData(row, "newOilOilStatNo", newOilOilStatCd);
		ds_oilUnitPrice.setCellData(row, "newQty", newQty);

        //submit 처리.
        let objSubmit = await $c.sbm.execute(sbm_adjust);

        if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
            await scwin.sbm_adjust_submitdone();
        }
	}
};

scwin.sbm_adjust_submitdone = async function (e) {
    await $c.win.alert("유류현물 선급금 내역을 성공적으로 분할하였습니다.");
	await scwin.f_Retrieve();
};


