scwin.udc_AllInOne_callBackFunc = function (rtnList) {
    let codeObj;
    let nameObj;

    if(scwin.udc_objNm == "") {
        codeObj = ed_eqModelCd;
        nameObj = ed_eqModelNm;
    } else if(scwin.udc_objNm == "") {
        codeObj = ed_clntNo;
        nameObj = ed_clntNm;
    } else if(scwin.udc_objNm == "udc_selpchClnt") {
        codeObj = ed_selpchClntNo;
        nameObj = ed_selpchClntNm;
    } else if(scwin.udc_objNm == "udc_bpClnt") {
        codeObj = ed_bpClntNo;
        nameObj = ed_bpClntNm;
    }

    $c.gus.cfSetReturnValue(rtnList, codeObj, nameObj);
};

scwin.f_chkOpenCommonPopUp  = async function (callObj, inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == undefined || isCode == true) {
	    await scwin.f_openCommonPopUp(callObj, disGubun, pVal, '', 'T', 'T');
    }
    // inObj가 코드명 필드일 경우 팝업
    else {
	    await scwin.f_openCommonPopUp(callObj, disGubun, '', pVal, 'T', 'T');
    }
};

//취소버튼 클릭시
scwin.f_cancel = function () {
    $c.data.undoRow(ds_oilUnitPrice, "Y");
};




scwin.ds_oilUnitPrice_onrowpositionchange = function (info) {
    var row = info.newRowIndex;
    if(ds_oilUnitPrice.getCellData(row,"fmsYn") == "Y"){
		gr_oilUnitPrice.setReadOnly("cell",row,'selfTransYn', true);				//자가운송여부
		gr_oilUnitPrice.setReadOnly("cell",row,'qty', true);				//수량
		gr_oilUnitPrice.setReadOnly("cell",row,'bpClntNo', true);				//운송거래처
	}else {
		gr_oilUnitPrice.setReadOnly("cell",row,'selfTransYn', false);					//자가운송여부
		gr_oilUnitPrice.setReadOnly("cell",row,'qty', false);					//수량
		gr_oilUnitPrice.setReadOnly("cell",row,'bpClntNo', false);					//운송거래처
        gr_oilUnitPrice.setCellInputType(row, "bpClntNo", {inputType : "textImage"});	
    }

	if (ds_oilUnitPrice.getCellData(row,"slipNo") != ""){
		gr_oilUnitPrice.setReadOnly("cell",row,'rmk', true);				//적요
		gr_oilUnitPrice.setReadOnly("cell",row,'slipDt', true);				//전표일자
	}else {
		if (ds_oilUnitPrice.getCellData(row,"payClsCd") == "10"){
			gr_oilUnitPrice.setReadOnly("cell",row,'rmk', false);
			gr_oilUnitPrice.setReadOnly("cell",row,'slipDt', false);
		} else if (ds_oilUnitPrice.getCellData(row,"payClsCd") == "01"){
			gr_oilUnitPrice.setReadOnly("cell",row,'rmk', true);
			gr_oilUnitPrice.setReadOnly("cell",row,'slipDt', true);
		}
	}
};


